arguments.command:
# Let's check bundleInfo and any other fields that might contain exception details
cd /tmp/sv-f012718362e94cf194ef331dfe90ac12 && python3 -c "
import json
lines = open('ios_crash.ips').readlines()
crash = json.loads(''.join(lines[1:]))

for key in ['bundleInfo', 'logWritingSignature', 'instructionByteStream', 'codeSigningAuxiliaryInfo']:
    if key in crash:
        val = crash[key]
        print(f'=== {key} ===')
        if isinstance(val, (dict, list)):
            print(json.dumps(val, indent=2)[:500])
        else:
            print(str(val)[:500])
        print()

# Also check if the lastExceptionBacktrace has any extra metadata
leb = crash.get('lastExceptionBacktrace', [])
if leb:
    # Check if there's flavor/type info
    if isinstance(leb, dict):
        print('lastExceptionBacktrace is dict:', json.dumps(leb, indent=2)[:500])
    elif isinstance(leb, list) and len(leb) > 0:
        print('lastExceptionBacktrace[0] keys:', list(leb[0].keys()) if isinstance(leb[0], dict) else type(leb[0]))
"

